var about=function(dnaDom){"use strict";const aboutCompany={team(){console.info("We have a team.")},mission(){console.info("Our mission is to not have a generic useless corporate mission statement.")}};const aboutHello={world(){console.info("Hello World.")}};const appConfig={apiServers:[{website:"localhost",api:"http://localhost:2121/api/v1/"}]};const utils={isCurrentWebsite(server){return server.website===globalThis.location.hostname}};const appLookup={apiServer:appConfig.apiServers.find(utils.isCurrentWebsite)?.api};const about={setup(){console.info("About",appLookup.apiServer);aboutHello.world();aboutCompany.mission()}};dnaDom.dna.dom.onReady(about.setup);return about}(globalThis);
